n = int(input())
inp = list(input().split())
gifts = []

for gift in inp:
  gifts.append(gift)
no_gift_count = 0

for i in range(n):
    received_gift = False
    for j in range(n):
        if i != j and gifts[i] < gifts[j]:
            received_gift = True
            break
    if not received_gift:
        no_gift_count += 1

print(no_gift_count)
